          description: 'Identify hosts responsible for volume changes',
          query: 'dataset="$DATASET" earliest=-1h\n| summarize Bytes=sum(orig_bytes) + sum(resp_bytes), Sessions=count() by id_orig_h\n| order by Bytes desc\n| limit 20'
