      objective: 'Detect when alert volume reaches levels that overwhelm analyst capacity or indicate sensor performance issues, risking missed detections.',
      severity: 'Critical',
      category: 'Capacity',
      tags: ['observability', 'capacity', 'alert-volume', 'sensor-health'],
